method LF_012_shrink_dynamic<T(0)>(fifo: LinearFifo<T>, size: nat)
  requires fifo.Valid()
  requires fifo.dynamic
  requires size >= fifo.count
  modifies fifo
  ensures fifo.Valid()
  ensures fifo.count == old(fifo.count)
  ensures fifo.ReadableModel() == old(fifo.ReadableModel())
  ensures fifo.capacity() == size
  ensures fifo.head == 0
{
  ghost var beforeContents := fifo.ReadableModel();
  ghost var beforeCount := fifo.count;
  fifo.shrink(size);
  assert fifo.Valid();
  assert fifo.count == beforeCount;
  assert fifo.ReadableModel() == beforeContents;
  assert fifo.capacity() == size;
  assert fifo.head == 0;
}

method LF_012_shrink_dynamic_to_count_witness<T(0)>(fifo: LinearFifo<T>)
  requires fifo.Valid()
  requires fifo.dynamic
  modifies fifo
  ensures fifo.Valid()
  ensures fifo.count == old(fifo.count)
  ensures fifo.ReadableModel() == old(fifo.ReadableModel())
  ensures fifo.capacity() == fifo.count
  ensures fifo.head == 0
{
  ghost var beforeContents := fifo.ReadableModel();
  ghost var beforeCount := fifo.count;
  fifo.shrink(fifo.count as nat);
  assert fifo.Valid();
  assert fifo.count == beforeCount;
  assert fifo.ReadableModel() == beforeContents;
  assert fifo.capacity() == beforeCount;
  assert fifo.head == 0;
}

method LF_012_shrink_dynamic_empty_to_zero_witness<T(0)>(fifo: LinearFifo<T>)
  requires fifo.Valid()
  requires fifo.dynamic
  requires fifo.count == 0
